/* ══════════════════════════════════════
       BLOCK: sidebar-help-support
       Scoped under .block-sidebar-help-support
       ══════════════════════════════════════ */

    body {
      font-family: 'Manrope', system-ui, sans-serif;
      margin: 0;
    }

    /* ── Card container ── */
    .block-sidebar-help-support {
      background-color: hsl(var(--brand-brand-beige, 20 23% 97%));
      border-radius: var(--rounded-2xl, 16px);
      padding: var(--spacing-2xl, 32px) 30px;
      display: flex;
      flex-direction: column;
      gap: var(--spacing-lg, 20px);
      overflow: hidden;
      width: 360px;
    }

    /* ── Header ── */
    .block-sidebar-help-support__title {
      font-size: var(--text-base-font-size, 18px);
      line-height: var(--text-base-line-height, 20px);
      letter-spacing: var(--text-base-letter-spacing, 0px);
      font-weight: var(--font-weight-semibold, 600);
      color: hsl(var(--text-primary, 0 0% 9%));
      border-bottom: 1px dashed hsl(var(--brand-gray-dd, 0 0% 87%));
      padding-bottom: var(--spacing-lg, 20px);
      margin: 0;
    }

    /* ── Styles for {{help_and_support}} hook output ──
       Hook renders: .help-and-support > .help-support-item > (.help-support-item__icon + .help-support-item__label)
       Label is <a> when value exists, <span> otherwise */
    .block-sidebar-help-support .help-and-support {
      display: flex;
      flex-direction: column;
    }

    .block-sidebar-help-support .help-support-item {
      display: flex;
      align-items: center;
      gap: var(--spacing-md);
      /* entrance animation */
      opacity: 0;
      transform: translateY(12px);
      transition: opacity 0.4s cubic-bezier(0.16, 1, 0.3, 1),
                  transform 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    }

    .block-sidebar-help-support .help-support-item.visible {
      opacity: 1;
      transform: translateY(0);
    }

    .block-sidebar-help-support .help-support-item__icon {
      width: 24px;
      height: 24px;
      flex-shrink: 0;
      object-fit: contain;
      opacity: 0.8;
    }

    .block-sidebar-help-support .help-support-item__label {
      font-size: var(--text-sm-font-size, 15px);
      line-height: var(--text-sm-line-height, 20px);
      letter-spacing: var(--text-sm-letter-spacing, 0px);
      font-weight: var(--font-weight-regular, 400);
      /* Figma: --brand-shades/700 #19227d ≈ --brand-cyan */
      color: hsl(var(--brand-cyan, 235 67% 29%));
      text-decoration: none;
      transition: opacity 0.15s ease;
    }

    a.help-support-item__label:hover {
      opacity: 0.75;
    }

js:
// Inject preview data if hook placeholder is still present (standalone preview)
    const block = document.querySelector('.block-sidebar-help-support');
    if (block && block.textContent.includes('{{help_and_support}}')) {
      const tpl = document.getElementById('preview-data');
      if (tpl) {
        block.innerHTML = block.innerHTML.replace('{{help_and_support}}', tpl.innerHTML);
      }
    }

    // Stagger reveal for items
    if (block) {
      const io = new IntersectionObserver((entries) => {
        entries.forEach(e => {
          if (e.isIntersecting) {
            e.target.classList.add('visible');
            io.unobserve(e.target);
          }
        });
      }, { threshold: 0.15 });
      block.querySelectorAll('.help-support-item').forEach((el, i) => {
        el.style.transitionDelay = `${i * 0.08}s`;
        io.observe(el);
      });
    }
